mapper.select:

where l.del_flag = '0'
AND l.applicant_user_id = #{applicantUserId}
AND l.approver_user_id = #{approverUserId}
AND l.leave_type = #{leaveType}
AND l.leave_status = #{leaveStatus}
AND l.leave_title like concat('%', #{leaveTitle}, '%')

    AND date_format(l.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


    AND date_format(l.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')

order by l.create_time desc


where l.del_flag = '0'
AND l.applicant_user_id = #{leaveApply.applicantUserId}
