AND l.leave_status = #{leaveApply.leaveStatus}
AND l.leave_title like concat('%', #{leaveApply.leaveTitle}, '%')

    AND date_format(l.create_time,'%Y%m%d') >= date_format(#{leaveApply.params.beginTime},'%Y%m%d')


    AND date_format(l.create_time,'%Y%m%d') <= date_format(#{leaveApply.params.endTime},'%Y%m%d')

